def process_graph(graph_data):
    graph_copy = graph_data.copy()

    # Find the EK_CONTROL_DOMAIN node with name ju1.s3.dom
    domain_node = None
    for node, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s3.dom' and 'EK_CONTROL_DOMAIN' in attrs.get('type', []):
            domain_node = node
            break

    if not domain_node:
        graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
        return_object = {
            'type': 'list',
            'data': [],
            'updated_graph': graph_json
        }
        return return_object

    # Find direct children via RK_CONTAINS edges
    children = []
    for successor in graph_copy.successors(domain_node):
        edge_data = graph_copy.get_edge_data(domain_node, successor)
        if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
            children.append(successor)

    # Calculate capacity for each child using iterative DFS
    child_capacities = []
    for child in children:
        total_capacity = 0
        stack = [child]
        visited = set()

        while stack:
            current = stack.pop()
            if current in visited:
                continue
            visited.add(current)

            attrs = graph_copy.nodes[current]
            # Add capacity if it's a PORT node
            if 'EK_PORT' in attrs.get('type', []) and 'physical_capacity_bps' in attrs:
                total_capacity += attrs['physical_capacity_bps']

            # Add all contained nodes to stack
            for successor in graph_copy.successors(current):
                edge_data = graph_copy.get_edge_data(current, successor)
                if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
                    stack.append(successor)

        child_name = graph_copy.nodes[child].get('name', child)
        child_capacities.append((child_name, total_capacity))

    # Sort by capacity descending
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': graph_json
    }

    return return_object

